const express = require('express');
const sgMail = require('@sendgrid/mail');

const app = express();
app.use(express.json());

// Load SendGrid API key from environment variable
const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;

if (!SENDGRID_API_KEY) {
  console.error('ERROR: SENDGRID_API_KEY environment variable is not set');
  process.exit(1);
}

sgMail.setApiKey(SENDGRID_API_KEY);

app.post('/send-email', async (req, res) => {
  try {
    const { to, from, subject, text, html } = req.body;

    if (!to || !from || !subject || (!text && !html)) {
      return res.status(400).json({
        error: 'Missing required fields: to, from, subject, and text or html'
      });
    }

    const msg = {
      to,
      from,
      subject,
      text,
      html
    };

    await sgMail.send(msg);

    res.status(200).json({
      success: true,
      message: 'Email sent successfully'
    });
  } catch (error) {
    console.error('Error sending email:', error);
    res.status(500).json({
      success: false,
      error: 'Failed to send email',
      details: error.message
    });
  }
});

app.get('/health', (req, res) => {
  res.status(200).json({ status: 'ok' });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Email notification service running on port ${PORT}`);
  console.log('SendGrid API key loaded from environment variable');
});

module.exports = app;